import React from "react";
import { motion } from "framer-motion";

export default function App() {
  return (
    <div className="bg-gradient-to-br from-gray-900 via-black to-gray-800 text-white min-h-screen">
      <Navbar />
      <Hero />
      <Experience />
      <Projects />
      <Contact />
    </div>
  );
}

function Navbar() {
  return (
    <div className="flex justify-between items-center px-10 py-5 backdrop-blur-md bg-white/5 sticky top-0">
      <h1 className="text-xl font-bold tracking-wide">Kashif.dev</h1>
      <div className="space-x-6">
        <a href="#exp">Experience</a>
        <a href="#projects">Projects</a>
        <a href="#contact">Contact</a>
      </div>
    </div>
  );
}

function Hero() {
  return (
    <div className="text-center py-32">
      <motion.h1 initial={{opacity:0,y:20}} animate={{opacity:1,y:0}} className="text-5xl font-bold">
        Full Stack Developer
      </motion.h1>
      <p className="mt-6 text-gray-400">Real-Time Systems | React | Node</p>
    </div>
  );
}

function Experience() {
  return (
    <div id="exp" className="px-10 py-20">
      <h2 className="text-3xl font-bold mb-10">Experience</h2>
      <div className="bg-white/5 p-8 rounded-2xl backdrop-blur-lg hover:scale-105 transition">
        <ul className="space-y-3 text-gray-300">
          <li>✔ Sensor integration & real-time systems</li>
          <li>✔ React Leaflet live air traffic monitoring</li>
          <li>✔ WebSockets, TCP, UDP</li>
          <li>✔ 24/7 high availability systems</li>
        </ul>
      </div>
    </div>
  );
}

function Projects() {
  return (
    <div id="projects" className="px-10 py-20">
      <h2 className="text-3xl font-bold mb-10">Projects</h2>
      <div className="grid md:grid-cols-2 gap-6">
        <Card title="Air Traffic System"/>
        <Card title="Map Drawing Tool"/>
      </div>
    </div>
  );
}

function Card({title}) {
  return (
    <div className="bg-white/5 p-6 rounded-2xl backdrop-blur-lg hover:scale-105 transition">
      <h3 className="text-xl font-semibold">{title}</h3>
    </div>
  );
}

function Contact() {
  return (
    <div id="contact" className="px-10 py-20">
      <h2 className="text-3xl font-bold mb-10">Contact</h2>
      <form className="space-y-4 max-w-lg">
        <input placeholder="Name" className="w-full p-3 rounded bg-black/40"/>
        <input placeholder="Email" className="w-full p-3 rounded bg-black/40"/>
        <textarea placeholder="Message" className="w-full p-3 rounded bg-black/40"/>
        <button className="bg-blue-600 px-6 py-2 rounded">Send</button>
      </form>
    </div>
  );
}
